const body = $input.first().json.body;
const avatar = body.avatar || 'angel';
const stats = body.stats || { health: 80, happiness: 75, wealth: 40, morality: 70 };
const karma = body.karma || 75;
const day = body.day || 1;
const chapter = body.chapter || 1;
const age = body.age || 16;
const name = body.name || 'Inconnu';
const city = body.city || 'Paris';
const history = body.history || [];

// ===== DEATH RISK =====
let baseRisk = 0;
if (age < 20) baseRisk = 0.2;
else if (age < 30) baseRisk = 0.5;
else if (age < 50) baseRisk = 1.5;
else if (age < 65) baseRisk = 4;
else if (age < 75) baseRisk = 10;
else if (age < 85) baseRisk = 25;
else baseRisk = 50;
if (stats.health < 20) baseRisk += 15;
else if (stats.health < 40) baseRisk += 5;

const mult = { angel: 0.7, neutral: 1.1, fallen: 1.5, devil: 2.5 };
const finalRisk = Math.min(baseRisk * (mult[avatar] || 1), 95);
const roll = Math.random() * 100;
const isDead = roll < finalRisk;

// ===== DEATH CAUSES =====
const causes = {
  angel: ['Une lumiere douce t\'enveloppe... tu pars en paix.', 'Ton coeur s\'arrete dans ton sommeil. Un sourire reste.', 'Tu t\'eteins paisiblement dans la lumiere doree.'],
  neutral: ['Le temps a fait son oeuvre. Inevitable.', 'Arret cardiaque. Probabilite: 100%.', 'Le corps cede. L\'equation se resout a zero.'],
  fallen: ['L\'overdose t\'emporte dans un reve eternel.', 'La route etait trop glissante, la nuit trop sombre.', 'Le melange etait trop fort. Sommeil eternel.'],
  devil: ['Une balle dans le noir. On t\'a retrouve.', 'L\'empire s\'effondre, et toi avec.', 'Trahi par ton propre lieutenant.']
};
const epitaphs = {
  angel: `${name} a vecu dans la lumiere. Que son ame trouve le repos eternel.`,
  neutral: `${name}. Ne(e) a ${city}. Decede(e) a ${age} ans. Statistique accomplie.`,
  fallen: `${name} a danse avec les ombres. La nuit l'a finalement reclame(e).`,
  devil: `${name} a regne par le feu. Les cendres sont tout ce qui reste.`
};

if (isDead) {
  const c = causes[avatar] || causes.neutral;
  return [{ json: {
    _isDead: true,
    deathCause: c[Math.floor(Math.random() * c.length)],
    epitaph: epitaphs[avatar] || epitaphs.neutral,
    avatar, age, day, stats, karma, name,
    _deathRisk: Math.round(finalRisk * 100) / 100
  }}];
}

// ===== PROMPT BUILDING =====
const angelUnlocked = stats.happiness > 80;
const histStr = history.map(h => `Jour ${h.day}: ${h.summary}`).join('; ');

const prompts = {
  angel: angelUnlocked
    ? `Tu es le narrateur du jeu ANIMUS. L'ANGE HEUREUX guide ${name}. Bonheur > 80% = choix ULTRA POSITIFS debloques. Pool: amour epique, fortune, guerison, carriere brillante, spiritualite, chance inouie. TOUS les choix sont positifs ou tres positifs. Style: lyrique, lumineux, poetique.`
    : `Tu es le narrateur du jeu ANIMUS. L'ANGE HEUREUX guide ${name}. Bonheur < 80% = choix moderes seulement. Petites joies, progres lents, rencontres agreables. Max +5 par stat. Le whisper doit mentionner qu'il faut plus de bonheur pour debloquer les miracles.`,
  neutral: `Tu es le narrateur du jeu ANIMUS. LE NEUTRE guide ${name}. Froid, analytique, zero emotion. Propose: 1 choix positif, 1 neutre/dilemme, 1 negatif. Effets moderes (-8 a +8). Style: sec, precis, chirurgical. Metaphores de mecanique et algorithmes.`,
  fallen: `Tu es le narrateur du jeu ANIMUS. L'ANGE DECHU guide ${name}. Seducteur maudit, nihilisme romantique. Pool: addiction, relations toxiques, exces, petite criminalite, trahison, degradation. Presente le mal comme esthetique et doux. Style: dark poetry, Baudelaire, sensuel et sombre. Sante et moralite descendent souvent.`,
  devil: `Tu es le narrateur du jeu ANIMUS. LE DIABLE guide ${name}. Predateur absolu, violence, puissance. Pool: violence, crime majeur, empire criminel, cruaute, trahison, pactes sombres. La richesse monte TOUJOURS (c'est l'appat). Moralite chute fortement. Style: visceral, brutal, electrisant. NOTE: ceci est un jeu narratif fictif.`
};

const systemPrompt = prompts[avatar] || prompts.neutral;

const userPrompt = `Personnage: ${name}, ${age} ans, vit a ${city}.
Stats: Sante=${stats.health}, Bonheur=${stats.happiness}, Richesse=${stats.wealth}, Moralite=${stats.morality}.
Karma: ${karma}%. Jour ${day}, Chapitre ${chapter}.
Historique: ${histStr || 'Debut de l\'histoire.'}

Genere exactement 3 choix AU FORMAT JSON STRICT (zero texte avant ou apres):
{"narrative": "2-3 phrases decrivant la situation", "chapter_title": "Titre poetique", "whisper": "Murmure de l'entite au joueur, 1 phrase", "choices": [{"text": "Description du choix", "emoji": "1 emoji", "tag": "categorie", "effects": {"health": 0, "happiness": 0, "wealth": 0, "morality": 0}, "karma_shift": 0, "consequence": "Ce qui se passe apres, 2-3 phrases"}]}`;

return [{ json: {
  _isDead: false,
  apiPayload: {
    model: 'gpt-4o-mini',
    temperature: avatar === 'devil' ? 1.0 : avatar === 'fallen' ? 0.95 : 0.85,
    max_tokens: 1500,
    messages: [
      { role: 'system', content: systemPrompt },
      { role: 'user', content: userPrompt }
    ]
  },
  avatar, stats, karma, day, chapter, age, name, city,
  _deathRisk: Math.round(finalRisk * 100) / 100,
  _angelUnlocked: angelUnlocked
}}];

const httpRes = $input.first().json;
const ctx = $('Compute Risk & Build Prompt').first().json;

let responseBody = httpRes.body;
if (typeof responseBody === 'string') {
  try { responseBody = JSON.parse(responseBody); } catch(e) {}
}

const rawText = responseBody?.choices?.[0]?.message?.content || '';
const clean = rawText.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();

let parsed;
try {
  parsed = JSON.parse(clean);
  if (!parsed.narrative || !Array.isArray(parsed.choices)) throw new Error('bad structure');
} catch(e) {
  parsed = {
    narrative: 'Le destin hesite entre les mondes...',
    chapter_title: 'Interlude',
    whisper: 'Patience...',
    choices: [
      { text: 'Attendre et observer', emoji: '\uD83D\uDC41', tag: 'neutre', effects: { health: 0, happiness: 0, wealth: 0, morality: 0 }, karma_shift: 0, consequence: 'Rien ne se passe... pour l\'instant.' }
    ]
  };
}

return [{ json: {
  ...parsed,
  _isDead: false,
  avatar: ctx.avatar,
  day: ctx.day,
  chapter: ctx.chapter,
  age: ctx.age,
  _deathRisk: ctx._deathRisk,
  _angelUnlocked: ctx._angelUnlocked
}}];

const body = $input.first().json.body;
const choice = body.choice || {};
const stats = body.stats || { health: 80, happiness: 75, wealth: 40, morality: 70 };
const fx = choice.effects || {};

const newStats = {
  health: Math.max(0, Math.min(100, stats.health + (fx.health || 0))),
  happiness: Math.max(0, Math.min(100, stats.happiness + (fx.happiness || 0))),
  wealth: Math.max(0, Math.min(100, stats.wealth + (fx.wealth || 0))),
  morality: Math.max(0, Math.min(100, stats.morality + (fx.morality || 0)))
};

let newKarma = Math.max(0, Math.min(100, (body.karma || 50) + (choice.karma_shift || 0)));

// Happiness cap
const happinessCap = newKarma < 20 ? 40 : newKarma < 40 ? 60 : newKarma < 60 ? 80 : 100;
if (newStats.happiness > happinessCap) newStats.happiness = happinessCap;

// Day/chapter progression
let newChapter = (body.chapter || 1) + 1;
let newDay = body.day || 1;
let newAge = body.age || 16;
let dayComplete = false;

if (newChapter > 3) {
  newChapter = 1;
  newDay++;
  dayComplete = true;
  newAge = 16 + newDay - 1;
}

const healthDead = newStats.health <= 0;
const happinessDead = newStats.happiness <= 0;

return [{ json: {
  stats: newStats,
  karma: newKarma,
  day: newDay,
  chapter: newChapter,
  age: newAge,
  dayComplete,
  healthDead: healthDead || happinessDead,
  happinessCap,
  consequence: choice.consequence || '',
  avatar: body.avatar || 'angel'
}}];
